(1058,	7,	'flexible_1_stories_0_heading',	'HERE\'S WHAT MAKES US DIFFERENT.'),
(1059,	7,	'_flexible_1_stories_0_heading',	'field_69eadb87fb9fa'),
(1060,	7,	'flexible_1_stories_0_content',	'Most marketing agencies give you a cookie- cutter plan and a dashboard that runs on autopilot. Elysium gives you a custom strategy built by a team of experts as invested in your success as you are.'),
