(1067,	7,	'_flexible_1_stories_0_card_title',	'field_69eadbe9fb9fe'),
(1068,	7,	'flexible_1_stories_0_card_body',	'Every campaign we run is tied to metrics that matter: leads, conversions, and revenue. Our results-driven approach means your strategy constantly adapts to real performance data—continuously, not just at your quarterly review.'),
