DROP TABLE IF EXISTS `wp_itsec_opaque_tokens`;
CREATE TABLE `wp_itsec_opaque_tokens` (
  `token_id` char(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
